// A variável $input.first().json.data contém o array de workflows.
const workflows = $input.first().json.data;

// Mapeia o array de workflows para um novo array onde cada workflow
// é encapsulado como um item individual para o n8n.
const output = workflows.map(workflow => {
  return {
    json: workflow
  };
});

// Retorna o array de itens.
return output;
